<script>
const labels=["Overview","Activity","Settings"];let active=$state(labels[0]);function activate(x){active=x}function navigate(e,x){const target=e.currentTarget;let i=labels.indexOf(x);if(e.key==='ArrowRight')i=(i+1)%labels.length;else if(e.key==='ArrowLeft')i=(i-1+labels.length)%labels.length;else if(e.key==='Home')i=0;else if(e.key==='End')i=labels.length-1;else if(true&&(e.key==='Enter'||e.key===' ')){activate(x);return}else return;e.preventDefault();const group=target?.parentElement;active=labels[i];queueMicrotask(()=>group?.querySelectorAll('[role=tab]')[i]?.focus())}
</script>
<main class="nav-shell"><h1>Tabs</h1><section><div class="tabs" role="tablist" aria-label="Account"><button role="tab" tabindex={active==="Overview"?0:-1} onclick={()=>activate("Overview")} onkeydown={(event)=>navigate(event,"Overview")} aria-selected={active==="Overview"}>Overview</button><button role="tab" tabindex={active==="Activity"?0:-1} onclick={()=>activate("Activity")} onkeydown={(event)=>navigate(event,"Activity")} aria-selected={active==="Activity"}>Activity</button><button role="tab" tabindex={active==="Settings"?0:-1} onclick={()=>activate("Settings")} onkeydown={(event)=>navigate(event,"Settings")} aria-selected={active==="Settings"}>Settings</button></div><div class="panel" role="tabpanel">{active} content</div></section></main>
